import{_ as a,o as t,c as n,a3 as o}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"35. Travelling And Reimbursement","description":"","frontmatter":{"title":"35. Travelling And Reimbursement","eba":"Mental Health Services 2024-2028","topics":["allowances","wages"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/allowances/35-travelling-and-reimbursement.md","filePath":"ebas/mental-health/common-terms/allowances/35-travelling-and-reimbursement.md"}'),r={name:"ebas/mental-health/common-terms/allowances/35-travelling-and-reimbursement.md"};function i(s,e,l,m,c,d){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_35-travelling-and-reimbursement" tabindex="-1">35. Travelling And Reimbursement <a class="header-anchor" href="#_35-travelling-and-reimbursement" aria-label="Permalink to &quot;35. Travelling And Reimbursement&quot;">​</a></h1><p><strong>35.1</strong> Living away from home</p><p><strong>(a)</strong> Where an Employee is required by their Employer to live away from their home, the Employee will be provided the following at the expense of the Employer:</p><p><strong>(i)</strong> reasonable accommodation, food and drinks; or</p><p><strong>(ii)</strong> if any of the benefits described in clause 35.1(a)(i)cannot be provided, payment of an equivalent allowance covering each benefit that is not provided. The allowance(s) will be calculated as follows: <strong>(A)</strong> at the maximum applicable rate determined by the ATO for the relevant benefit (i.e. food, drink and/or accommodation expenses) from time to time; or <strong>(B)</strong> if the amount paid by the Employee for accommodation, food or drink exceeds the ATO guideline amount and was reasonably incurred, the total cost of the accommodation, food and/or drink, subject to the Employee providing reasonable evidence to substantiate the cost(s) and their reasonableness. Note: For vehicle allowances, see <a href="/eba/ebas/mental-health/common-terms/allowances/34-vehicle-allowance.html">clause 34</a>.</p><p><strong>35.2</strong> Special provisions relating to particular travel</p><p><strong>(a)</strong> Any Employee engaged for a distant position where a definite period of engagement is not stated shall after six months&#39; continuous service, receive a refund of reasonable railway or bus fares and reasonable out-of-pocket expenses incurred within the State of Victoria in reaching such position.</p><p><strong>(b)</strong> Any Employee engaged for a distant position for a definite period shall, upon completion of the term of the engagement, receive reasonable railway, coach or plane fares or necessary mileage for use of private car for return trip or reasonable out-of-pocket expenses incurred in travelling within the State of Victoria.</p><p>Plain language terms: travel expenses, travel reimbursement, mileage.</p>',9)])])}const f=a(r,[["render",i]]);export{h as __pageData,f as default};
